// And groups predicates with the AND operator between them.
func And(predicates ...predicate.RobotMCPServer) predicate.RobotMCPServer {
	return predicate.RobotMCPServer(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.RobotMCPServer) predicate.RobotMCPServer {
	return predicate.RobotMCPServer(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.RobotMCPServer) predicate.RobotMCPServer {
	return predicate.RobotMCPServer(sql.NotPredicates(p))
}
